1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	type NeighborEntry = { cell: Cell; count: number };
12	
13	function tallyNeighbors(cells: Cell[]): Map<string, NeighborEntry> {
14	  const tally = new Map<string, NeighborEntry>();
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const key = keyOf(neighbor);
19	      const entry = tally.get(key);
20	      if (entry) entry.count++;
21	      else tally.set(key, { cell: neighbor, count: 1 });
22	    }
23	  }
24	  return tally;
25	}
26	
27	function survives(isAlive: boolean, neighborCount: number): boolean {
28	  return neighborCount === 3 || (isAlive && neighborCount === 2);
29	}
30	
31	export function nextGeneration(cells: Cell[]): Cell[] {
32	  const alive = new Set(cells.map(keyOf));
33	  const tally = tallyNeighbors(cells);
34	  const result: Cell[] = [];
35	  for (const [key, { cell, count }] of tally) {
36	    if (survives(alive.has(key), count)) result.push(cell);
37	  }
38	  return result;
39	}
